#ifndef ESP_NOW_PEER_H
#define ESP_NOW_PEER_H
void espnow_setup();
void espnow_loop();
bool espnow_send(const uint8_t* mac, const uint8_t* data, size_t len);
typedef void (*espnow_rx_cb)(const uint8_t* data, int len);
void espnow_on_receive(espnow_rx_cb cb);
#endif

firmware_template.source:
#include "esp_now_peer.h"
#include <WiFi.h>
#include <esp_now.h>
static espnow_rx_cb _rx_cb=nullptr;
void _on_recv(const uint8_t*mac,const uint8_t*data,int len){if(_rx_cb)_rx_cb(data,len);}
void espnow_setup(){
  WiFi.mode(WIFI_STA);
  if(esp_now_init()!=ESP_OK){Serial.println("[espnow] Init failed!");return;}
  esp_now_register_recv_cb(_on_recv);
  Serial.printf("[espnow] OK MAC: %s\n",WiFi.macAddress().c_str());
}
void espnow_loop(){}
bool espnow_send(const uint8_t*mac,const uint8_t*data,size_t len){
  esp_now_peer_info_t p={};memcpy(p.peer_addr,mac,6);p.channel=0;p.encrypt=false;
  if(!esp_now_is_peer_exist(mac))esp_now_add_peer(&p);
  return esp_now_send(mac,data,len)==ESP_OK;
}
void espnow_on_receive(espnow_rx_cb cb){_rx_cb=cb;}
